import type { Metadata } from "next";

import LotTraceability from "./LotTraceability";

export const metadata: Metadata = {
    title: "ロット追跡 / トレーサビリティ | ぐんじょう",
    description:
        "製造業向けのロット追跡・トレーサビリティ画面。製品ロットの概要（ロット番号 / 品名 / 製造日 / 数量 / ステータス / 製造ライン）、上流（投入原料ロット）と下流（出荷ロット）を双方向に辿るロット系譜、リコール範囲の特定と確定、入出庫・工程履歴の監査証跡、出荷先一覧を備えた品質保証 / 生産管理者向けの画面です。",
};

export default function LotTraceabilityPage() {
    return <LotTraceability />;
}

"use client"

import * as React from "react"
import {
    IconArrowBackUp,
    IconArrowForwardUp,
    IconBox,
    IconBuildingFactory2,
    IconFlask,
    IconTruckDelivery,
} from "@tabler/icons-react"
import { Badge, Icon, TreeView, type TreeNode } from "@gunjo/ui"

import { LOT_STATUS, type GenealogyNode } from "./data"

const KIND_ICON = {
    material: IconFlask,
    intermediate: IconBox,
    product: IconBuildingFactory2,
    shipment: IconTruckDelivery,
} as const

/**
 * Map a domain GenealogyNode into a @gunjo/ui TreeNode. The label carries the
 * lot number + name + a status Badge (which is icon/text-bearing, not colour
 * only). `sharedWith` is surfaced because a strict tree can't draw the cross-
 * link of the underlying DAG.
 */
function toTreeNode(node: GenealogyNode): TreeNode {
    const status = LOT_STATUS[node.status]
    const KindGlyph = KIND_ICON[node.kind]
    return {
        id: node.id,
        icon: <Icon icon={KindGlyph} size="sm" className="text-muted-foreground" />,
        label: (
            <span className="flex min-w-0 flex-col gap-0.5 py-0.5">
                <span className="flex flex-wrap items-center gap-2">
                    <span className="font-mono text-xs font-semibold tabular-nums text-foreground">
                        {node.lotNo}
                    </span>
                    <Badge variant={status.badge}>
                        {status.label}
                        <span className="sr-only"> （{status.code}）</span>
                    </Badge>
                </span>
                <span className="truncate text-sm font-normal text-foreground">{node.name}</span>
                <span className="flex flex-wrap gap-x-3 gap-y-0.5 text-xs font-normal text-muted-foreground">
                    {node.party ? <span>{node.party}</span> : null}
                    {node.qty ? <span className="tabular-nums">{node.qty}</span> : null}
                    {node.date ? <span className="tabular-nums">{node.date}</span> : null}
                </span>
                {node.sharedWith ? (
                    <span className="text-xs font-medium text-warning">
                        ⚠ 共有ロット — {node.sharedWith}
                    </span>
                ) : null}
            </span>
        ),
        children: node.children?.map(toTreeNode),
    }
}

function collectIds(nodes: GenealogyNode[]): string[] {
    return nodes.flatMap((n) => [n.id, ...(n.children ? collectIds(n.children) : [])])
}

export interface GenealogyTreeProps {
    direction: "upstream" | "downstream"
    nodes: GenealogyNode[]
    /** Lot number of the subject lot, shown as the fixed root of the chain. */
    subjectLotNo: string
}

/**
 * One direction of the lot-genealogy chain. Upstream traces material lots that
 * were consumed INTO the subject lot (前へ遡る); downstream traces lots /
 * shipments produced OUT of it (後ろへ追う). Built on @gunjo/ui TreeView.
 */
export function GenealogyTree({ direction, nodes, subjectLotNo }: GenealogyTreeProps) {
    const isUpstream = direction === "upstream"
    const treeNodes = React.useMemo(() => nodes.map(toTreeNode), [nodes])
    const allIds = React.useMemo(() => collectIds(nodes), [nodes])
    const heading = isUpstream ? "上流トレース（前へ遡る）" : "下流トレース（後ろへ追う）"
    const sub = isUpstream
        ? "このロットに投入された原料・資材ロット"
        : "このロットから生まれた製品ロット・出荷"
    const DirIcon = isUpstream ? IconArrowBackUp : IconArrowForwardUp

    return (
        <section aria-label={heading} className="flex min-w-0 flex-1 flex-col gap-3">
            <header className="flex flex-col gap-1">
                <h3 className="flex items-center gap-2 text-sm font-semibold text-foreground">
                    <Icon icon={DirIcon} size="sm" aria-hidden />
                    {heading}
                </h3>
                <p className="text-xs text-muted-foreground">{sub}</p>
            </header>

            {/* Fixed root = the subject lot, so the user always sees the anchor of the chain. */}
            <div className="flex items-center gap-2 rounded-md border border-primary/40 bg-primary/5 px-3 py-2">
                <Icon icon={IconBuildingFactory2} size="sm" className="text-primary" aria-hidden />
                <span className="font-mono text-xs font-semibold tabular-nums text-foreground">
                    {subjectLotNo}
                </span>
                <span className="text-xs text-muted-foreground">（対象ロット）</span>
            </div>

            <div
                className="rounded-md border border-border bg-card p-2"
                role="group"
                aria-label={isUpstream ? "原料ロットの系譜" : "出荷ロットの系譜"}
            >
                <TreeView
                    nodes={treeNodes}
                    defaultExpanded={allIds}
                    selectionMode="none"
                />
            </div>
        </section>
    )
}
